sql:
SELECT episode_title
FROM podcast_episodes
WHERE strftime('%Y-%m', release_date) = '2023-05';

SELECT episode_id, transcript_text
FROM episode_transcripts
WHERE transcript_date > '2023-01-01';

external_knowledge:
Metric for engagement; 
Popularity refers to the number of unique users who played the episode; 
Positive feedback refers to ratings of 4 or higher; 
Sharing activity refers to the number of times the episode was shared on social media platforms; 
Overall impact includes the number of distinct platforms on which the episode was shared.

sql:
SELECT COUNT(*) 
FROM podcast_episodes 
WHERE strftime('%Y', 'now') - strftime('%Y', release_date) <= 1;

SELECT COUNT(*) AS total_shares
FROM social_media_shares
WHERE platform = 'Twitter';

SELECT series_id, COUNT(*) AS episode_count
FROM podcast_episodes
GROUP BY series_id;

SELECT platform, share_date
FROM social_media_shares
WHERE episode_id = 0 AND share_date BETWEEN '2023-05-01' AND '2023-05-02';

SELECT series_name
FROM podcast_series
WHERE category = 'Urban Planning';

SELECT series_name, series_theme, category, sub_category
FROM podcast_series
WHERE series_id = 1;

SELECT episode_title, episode_duration
FROM podcast_episodes
WHERE episode_id = 0;

SELECT user_id, COUNT(episode_id) AS recommendation_count
FROM episode_recommendations
GROUP BY user_id;

SELECT user_name
FROM users
WHERE user_id IN (
  SELECT DISTINCT user_id
  FROM episode_comments
);
